    @app.route("/api/config", methods=["POST"])
    def api_config_set():
        import config as cfg

        body = request.get_json(silent=True) or {}
        # Share the schema-driven settings write lock so an autosave in the
        # All-settings region can't race with the curated form's full-snapshot
        # save and silently overwrite a recently-saved schema value.
        with _settings_write_lock:
            current = cfg.load()

            # Handle keyboard_shortcuts with validation
            if "keyboard_shortcuts" in body:
                shortcuts = body["keyboard_shortcuts"]
                if isinstance(shortcuts, dict):
                    valid_contexts = cfg.DEFAULTS["keyboard_shortcuts"]
                    validated = {}
                    for ctx_name, actions in shortcuts.items():
                        if ctx_name in valid_contexts and isinstance(actions, dict):
                            validated[ctx_name] = {}
                            for action, key_str in actions.items():
                                if action in valid_contexts[ctx_name] and isinstance(key_str, str):
                                    validated[ctx_name][action] = key_str.strip().lower()
                    current["keyboard_shortcuts"] = cfg._deep_merge(
                        cfg.DEFAULTS["keyboard_shortcuts"], validated
                    )

            # Normalize remote_targets on save (assign stable ids, coerce
            # field types, drop unusable entries) so stored entries always
            # have the shape get_remote_targets() guarantees on read.
            if "remote_targets" in body:
                raw_targets = body["remote_targets"]
                normalized = []
                if isinstance(raw_targets, list):
                    import uuid
                    for entry in raw_targets:
                        coerced = cfg._coerce_remote_target(entry)
                        if coerced is None:
                            continue
                        # A client-supplied id wins (stable across edits);
                        # otherwise mint one so future edits can key the row.
                        if not (isinstance(entry, dict) and (entry.get("id") or "").strip()):
                            coerced["id"] = uuid.uuid4().hex
                        normalized.append(coerced)
                current["remote_targets"] = normalized

            for key in body:
                if key in ("keyboard_shortcuts", "remote_targets"):
                    continue
                if key in cfg.DEFAULTS:
                    current[key] = body[key]
            # Apply HF token to environment immediately
            hf_token = current.get("hf_token", "")
            if hf_token:
                os.environ["HF_TOKEN"] = hf_token
            elif "HF_TOKEN" in os.environ:
                del os.environ["HF_TOKEN"]
            cfg.save(current)
            # If the user shrunk the preview cache quota, evict immediately to the
            # new size rather than waiting for the next cache write. No-op when
            # already under quota, so always safe to call.
            vireo_dir = os.path.dirname(app.config["THUMB_CACHE_DIR"])
            evict_preview_cache_if_over_quota(_get_db(), vireo_dir)
        return jsonify({"ok": True})

    @app.route("/api/settings/schema")
    def api_settings_schema():
        """Return the SCHEMA dict and the ordered category list.

        Consumed by the schema-rendered settings UI to generate widgets.
        """
        import config_schema as schema

        return jsonify({
            "schema": schema.SCHEMA,
            "categories": list(schema.CATEGORIES),
        })

    @app.route("/api/settings/values")
    def api_settings_values():
        """Return values across all four layers (default / global / workspace / effective).

        Each layer is a dotted-flat dict, restricted to keys present in SCHEMA.
        Keys hand-edited into config.json or stored as workspace metadata
        (e.g. active_labels) that are not declared in SCHEMA are intentionally
        omitted from the response so they don't show up as "overridden" in
        the UI; they are preserved on disk and visible in the raw-JSON tab.
        """
        import config as cfg
        import config_schema as schema

        schema_keys = set(schema.SCHEMA.keys())

        # Default layer: flatten DEFAULTS, restrict to schema keys.
        default_flat = schema.flatten(cfg.DEFAULTS)
        default_layer = {k: default_flat[k] for k in schema_keys if k in default_flat}

        # Global layer: read the raw file (not cfg.load(), which deep-merges
        # with DEFAULTS — we want only what the user explicitly set). Also
        # filter out keys whose value equals the default: legacy save paths
        # write the entire deep-merged config, but a value matching the
        # default is not really a user override and should not show as one.
        global_flat = schema.flatten(_read_raw_config_file())
        global_layer = {
            k: v for k, v in global_flat.items()
            if k in schema_keys and default_layer.get(k) != v
        }

        # Workspace layer: parse config_overrides for the active workspace.
        workspace_layer = {}
        db = _get_db()
        ws = db.get_workspace(db._active_workspace_id)
        if ws and ws["config_overrides"]:
            try:
                overrides = (
                    json.loads(ws["config_overrides"])
                    if isinstance(ws["config_overrides"], str)
                    else ws["config_overrides"]
                )
                ws_flat = schema.flatten(overrides if isinstance(overrides, dict) else {})
                # Filter out global-only schema keys: workspace create/update
                # APIs can persist arbitrary override payloads, so a workspace
                # may contain entries for keys whose scope is "global".
                # Runtime paths for those keys read global config only, so
                # surfacing the workspace value here would mislead the UI
                # into showing a workspace-effective value that is never
                # actually applied.
                workspace_layer = {
                    k: v for k, v in ws_flat.items()
                    if k in schema_keys
                    and schema.SCHEMA[k].get("scope") != "global"
                }
            except (json.JSONDecodeError, TypeError):
                workspace_layer = {}

        # Effective layer: workspace > global > default for every schema key.
        effective_layer = {}
        for k in schema_keys:
            if k in workspace_layer:
                effective_layer[k] = workspace_layer[k]
            elif k in global_layer:
                effective_layer[k] = global_layer[k]
            elif k in default_layer:
                effective_layer[k] = default_layer[k]

        return jsonify({
            "default": default_layer,
            "global": global_layer,
            "workspace": workspace_layer,
            "effective": effective_layer,
        })

    def _settings_post_save_side_effects(current):
        """Side effects mirrored from the legacy /api/config POST handler.

        Keeps the new schema-driven write path behaviorally identical to the
        old curated-form save: HF_TOKEN env var is kept in sync, and the
        preview cache is evicted if its budget shrunk.
        """
        hf_token = current.get("hf_token", "")
        if hf_token:
            os.environ["HF_TOKEN"] = hf_token
        elif "HF_TOKEN" in os.environ:
            del os.environ["HF_TOKEN"]
        vireo_dir = os.path.dirname(app.config["THUMB_CACHE_DIR"])
        evict_preview_cache_if_over_quota(_get_db(), vireo_dir)

    def _read_raw_config_file():
        """Return the parsed contents of ~/.vireo/config.json, or {}.

        Unlike cfg.load(), this does NOT merge DEFAULTS — so it contains
        only the keys the user has actually set. Used by write paths so the
        on-disk file stays minimal.
        """
        import config as cfg

        if not os.path.exists(cfg.CONFIG_PATH):
            return {}
        try:
            with open(cfg.CONFIG_PATH) as f:
                raw = json.load(f)
            return raw if isinstance(raw, dict) else {}
        except (OSError, json.JSONDecodeError):
            return {}

    # Serializes read-modify-write of ~/.vireo/config.json and the active
    # workspace's config_overrides across the schema-driven settings
    # endpoints (PATCH/DELETE/import). Without this, with per-field autosave
    # and `app.run(threaded=True)` two concurrent requests can read the same
    # snapshot and the later writer drops the earlier change.
    _settings_write_lock = threading.Lock()

    @app.route("/api/settings/global", methods=["PATCH"])
    def api_settings_global_patch():
        """Set a single global config value (validated against SCHEMA)."""
        import config as cfg
        import config_schema as schema

        body = request.get_json(silent=True) or {}
        key = body.get("key")
        if not isinstance(key, str) or key not in schema.SCHEMA:
            return json_error(f"unknown setting {key!r}", status=400)
        try:
            value = schema.validate_value(key, body.get("value"))
        except schema.ValidationError as e:
            return json_error(str(e), status=400)

        with _settings_write_lock:
            raw = _read_raw_config_file()
            schema.set_dotted(raw, key, value)
            cfg.save(raw)
            _settings_post_save_side_effects(cfg.load())
        return jsonify({"ok": True, "key": key, "value": value})

    @app.route("/api/settings/global/<path:key>", methods=["DELETE"])
    def api_settings_global_delete(key):
        """Remove a key from the global config file (reverts to default)."""
        import config as cfg
        import config_schema as schema

        if key not in schema.SCHEMA:
            return json_error(f"unknown setting {key!r}", status=400)

        with _settings_write_lock:
            raw = _read_raw_config_file()
            schema.delete_dotted(raw, key)
            cfg.save(raw)
            _settings_post_save_side_effects(cfg.load())
        return jsonify({"ok": True, "key": key})

    def _read_workspace_overrides(db):
        """Return the active workspace's config_overrides as a dict (or {}).

        Coerces non-dict payloads (possible via legacy workspace
        create/update APIs) to ``{}`` so dotted-key mutation in the schema
        write paths can't crash on a malformed override.
        """
        ws = db.get_workspace(db._active_workspace_id)
        if not ws or not ws["config_overrides"]:
            return {}
        try:
            raw = ws["config_overrides"]
            parsed = json.loads(raw) if isinstance(raw, str) else raw
        except (json.JSONDecodeError, TypeError):
            return {}
        return parsed if isinstance(parsed, dict) else {}

    def _write_workspace_overrides(db, overrides):
        db.update_workspace(
            db._active_workspace_id,
            config_overrides=overrides if overrides else None,
        )

    @app.route("/api/settings/workspace", methods=["PATCH"])
    def api_settings_workspace_patch():
        """Set a single per-workspace override (validated against SCHEMA)."""
        import config_schema as schema

        body = request.get_json(silent=True) or {}
        key = body.get("key")
        if not isinstance(key, str) or key not in schema.SCHEMA:
            return json_error(f"unknown setting {key!r}", status=400)
        if schema.SCHEMA[key].get("scope") == "global":
            return json_error(
                f"{key!r} is global-only and cannot be overridden per workspace",
                status=400,
            )
        try:
            value = schema.validate_value(key, body.get("value"))
        except schema.ValidationError as e:
            return json_error(str(e), status=400)

        db = _get_db()
        with _settings_write_lock:
            overrides = _read_workspace_overrides(db)
            schema.set_dotted(overrides, key, value)
            _write_workspace_overrides(db, overrides)
        return jsonify({"ok": True, "key": key, "value": value})

    @app.route("/api/settings/workspace/<path:key>", methods=["DELETE"])
    def api_settings_workspace_delete(key):
        """Remove a per-workspace override (the key falls back to global/default)."""
        import config_schema as schema

        if key not in schema.SCHEMA:
            return json_error(f"unknown setting {key!r}", status=400)
        db = _get_db()
        with _settings_write_lock:
            overrides = _read_workspace_overrides(db)
            schema.delete_dotted(overrides, key)
            _write_workspace_overrides(db, overrides)
        return jsonify({"ok": True, "key": key})

    @app.route("/api/settings/export")
    def api_settings_export():
        """Download ~/.vireo/config.json as an attachment.

        Returns the raw user-overrides file (or "{}" if absent), pretty-printed.
        Workspace overrides are not included — they're per-workspace state, not
        global config.
        """
        import datetime as _datetime

        raw = _read_raw_config_file()
        raw.pop("_migrations_applied", None)
        body = json.dumps(raw, indent=2)
        today = _datetime.date.today().isoformat()
        resp = make_response(body)
        resp.headers["Content-Type"] = "application/json"
        resp.headers["Content-Disposition"] = (
            f'attachment; filename="vireo-config-{today}.json"'
        )
        return resp

    @app.route("/api/settings/import", methods=["POST"])
    def api_settings_import():
        """Replace ~/.vireo/config.json with the supplied JSON payload.

        Validates every schema-known leaf key in the payload before writing;
        on any validation failure, returns 400 with a per-key error map and
        leaves the file untouched. Non-schema keys (setup_complete, the
        keyboard_shortcuts subtree, etc.) pass through unchanged so that
        backups round-trip cleanly. Workspace overrides are untouched —
        backups capture global state only.
        """
        import config as cfg
        import config_schema as schema

        body = request.get_json(silent=True) or {}
        raw_text = body.get("json", "")
        if not isinstance(raw_text, str):
            return json_error("body.json must be a string", status=400)
        try:
            payload = json.loads(raw_text)
        except json.JSONDecodeError as e:
            return json_error(f"invalid JSON: {e}", status=400)
        if not isinstance(payload, dict):
            return json_error("payload must be a JSON object", status=400)

        # Iterate the schema directly rather than relying on flatten() — empty
        # objects at schema leaves (e.g. {"classification_threshold": {}}) flatten
        # to nothing and would otherwise be written as-is, replacing a numeric
        # leaf with {} on disk and breaking downstream consumers.
        _MISSING = object()
        errors = {}

        # 1. Reject scalars where a schema-backed object subtree is expected
        #    (e.g. {"pipeline": 5}).
        for prefix in schema.schema_parent_prefixes():
            val = schema.get_dotted(payload, prefix, default=_MISSING)
            if val is _MISSING or isinstance(val, dict):
                continue
            errors[prefix] = f"{prefix} must be a JSON object"

        # 2. For every schema leaf actually present in the payload, reject any
        #    object (empty or otherwise) and run the usual value validation.
        for schema_key in schema.SCHEMA:
            val = schema.get_dotted(payload, schema_key, default=_MISSING)
            if val is _MISSING:
                continue
            if isinstance(val, dict):
                errors[schema_key] = f"{schema_key} must be a JSON scalar, not an object"
                continue
            try:
                coerced = schema.validate_value(schema_key, val)
                schema.set_dotted(payload, schema_key, coerced)
            except schema.ValidationError as e:
                errors[schema_key] = str(e)

        # Structured non-schema keys still need shape validation, otherwise a
        # malformed payload would write through to the file and crash
        # downstream UI consumers that assume a specific shape.
        if "keyboard_shortcuts" in payload:
            # shortcuts.html dereferences `cfg.keyboard_shortcuts.<ctx>.<action>`
            # and assumes a dict tree.
            ks = payload["keyboard_shortcuts"]
            if not isinstance(ks, dict):
                errors["keyboard_shortcuts"] = "keyboard_shortcuts must be a JSON object"
            else:
                for ctx_name, actions in ks.items():
                    if not isinstance(actions, dict):
                        errors[f"keyboard_shortcuts.{ctx_name}"] = (
                            f"keyboard_shortcuts.{ctx_name} must be a JSON object"
                        )
                        continue
                    for action, key_str in actions.items():
                        if not isinstance(key_str, str):
                            errors[f"keyboard_shortcuts.{ctx_name}.{action}"] = (
                                "must be a string"
                            )

        # ingest.recent_destinations is also EXCLUDED from SCHEMA but is a
        # structured value (list[str]). pipeline.html calls
        # `recents.forEach(...)` on it, so a non-list value would crash the
        # pipeline page after a bad import.
        ingest_section = payload.get("ingest")
        if isinstance(ingest_section, dict) and "recent_destinations" in ingest_section:
            recents = ingest_section["recent_destinations"]
            if not isinstance(recents, list):
                errors["ingest.recent_destinations"] = (
                    "ingest.recent_destinations must be a JSON array"
                )
            else:
                for i, item in enumerate(recents):
                    if not isinstance(item, str):
                        errors[f"ingest.recent_destinations[{i}]"] = (
                            "must be a string"
                        )
                        break

        if errors:
            return jsonify({"error": "validation failed", "errors": errors}), 400

        with _settings_write_lock:
            cfg.save(payload)
            _settings_post_save_side_effects(cfg.load())
        return jsonify({"ok": True})

    @app.route("/api/darktable/status")
    def api_darktable_status():
        import config as cfg
        from develop import find_darktable, find_dng_converter

        configured = cfg.get("darktable_bin")
        binary = find_darktable(configured)
        dng_configured = cfg.get("dng_converter_bin")
        dng_binary = find_dng_converter(dng_configured)
        return jsonify({
            "available": binary is not None,
            "bin": binary or "",
            "configured_bin": configured,
            "dng_available": dng_binary is not None,
            "dng_bin": dng_binary or "",
            "configured_dng_bin": dng_configured,
            "auto_convert_dng": cfg.get("darktable_auto_convert_dng"),
            "style": cfg.get("darktable_style"),
            "output_format": cfg.get("darktable_output_format"),
            "output_dir": cfg.get("darktable_output_dir"),
        })

    @app.route("/api/exiftool/status")
    def api_exiftool_status():
        """Report whether the exiftool binary is installed.

        exiftool is the metadata backbone for every scan (capture date, GPS,
        camera/lens, dimensions). When it's absent scans still complete but
        produce no metadata, so the welcome flow and Settings surface this
        check up-front rather than letting the failure stay silent in the log.
        """
        from metadata import exiftool_status
        return jsonify(exiftool_status())

    @app.route("/api/photos/open-external", methods=["POST"])
    def api_photos_open_external():
        import subprocess
        import sys

        import config as cfg

        body = request.get_json(silent=True) or {}
        photo_ids = body.get("photo_ids")
        if not isinstance(photo_ids, list) or not photo_ids:
            return json_error("photo_ids required")
        if not all(isinstance(pid, int) for pid in photo_ids):
            return json_error("photo_ids must be a list of integers")

        db = _get_db()
        folders = {f["id"]: f["path"] for f in db.get_folder_tree()}
        vireo_dir = os.path.dirname(app.config["THUMB_CACHE_DIR"])
        photo_paths = []
        for pid in photo_ids:
            photo = db.get_photo(pid)
            if not photo:
                continue
            folder_path = folders.get(photo["folder_id"], "")
            if folder_path:
                photo_paths.append((
                    photo,
                    os.path.join(folder_path, photo["filename"]),
                ))

        if not photo_paths:
            return json_error("No photos found", 404)

        def _external_edit_recipe_source(photo, recipe, fallback_path):
            from image_loader import RAW_EXTENSIONS

            primary_is_raw = (
                os.path.splitext(photo["filename"])[1].lower() in RAW_EXTENSIONS
            )

            if recipe.get("crop"):
                source_path, _using_working_copy = _recipe_render_source(
                    photo, recipe, 0, vireo_dir, folders,
                )
                return source_path or fallback_path

            # For RAW primaries, skip the working-copy short-circuit while the
            # RAW source is available: legacy working copies predate the
            # highlight-preserving RAW decode and would feed the editor a
            # clipped JPEG to apply the recipe to. If the RAW source is
            # offline/missing, the working copy is the only local fallback.
            wc_rel = photo["working_copy_path"]
            if wc_rel and (
                not primary_is_raw or not os.path.exists(fallback_path)
            ):
                wc_path = (
                    wc_rel if os.path.isabs(wc_rel)
                    else os.path.join(vireo_dir, wc_rel)
                )
                if (
                    os.path.exists(wc_path)
                    and _path_satisfies_recipe_render(wc_path, photo, recipe, 0)
                ):
                    return wc_path

            folder_path = folders.get(photo["folder_id"])
            if folder_path:
                raw_source_available = os.path.exists(fallback_path)
                # For RAW primaries, skip the companion JPEG while the RAW is
                # available so edits render from the preserve-highlights decode.
                # If the RAW volume is offline, a full-size sidecar is the best
                # remaining local source.
                if not primary_is_raw or not raw_source_available:
                    companion_path = photo["companion_path"]
                    if companion_path:
                        companion = os.path.join(folder_path, companion_path)
                        if (
                            os.path.exists(companion)
                            and _path_satisfies_recipe_render(
                                companion, photo, recipe, 0,
                            )
                        ):
                            return companion
                original = os.path.join(folder_path, photo["filename"])
                if os.path.exists(original):
                    return original
            return fallback_path

        def _external_edit_handoff_path(photo, fallback_path):
            recipe = db.get_photo_edit_recipe(photo["id"])
            if not recipe:
                return fallback_path, None

            import local_masks as _local_masks
            from image_edits import (
                EDIT_MATH_VERSION,
                apply_recipe_to_loaded_image,
                recipe_to_json,
            )
            from image_loader import (
                RAW_DECODE_PRESERVE_HIGHLIGHTS,
                RAW_EXTENSIONS,
                load_image,
            )

            source_path = _external_edit_recipe_source(
                photo, recipe, fallback_path,
            )
            if not source_path or not os.path.isfile(source_path):
                return None, f"{photo['filename']}: source file missing"

            out_dir = os.path.join(vireo_dir, "external-edits")
            os.makedirs(out_dir, exist_ok=True)
            out_path = os.path.join(out_dir, f"{photo['id']}.jpg")
            meta_path = os.path.join(out_dir, f"{photo['id']}.json")
            source_mtime = os.path.getmtime(source_path)
            recipe_json = recipe_to_json(recipe) or ""
            # Include the edit-math version so a math bump invalidates this
            # handoff render: the JPEG is keyed by recipe/source/mtime, none
            # of which change when only the per-pixel rendering math changes,
            # so without this we'd keep handing editors the stale render.
            expected_meta = {
                "recipe": recipe_json,
                "source_path": source_path,
                "source_mtime": source_mtime,
                "edit_math_version": EDIT_MATH_VERSION,
            }
            try:
                if os.path.isfile(out_path) and os.path.isfile(meta_path):
                    with open(meta_path, encoding="utf-8") as f:
                        cached_meta = json.load(f)
                    if cached_meta == expected_meta:
                        return out_path, None
            except (OSError, ValueError, TypeError):
                pass

            # Derive the decode mode from the primary photo's extension rather
            # than source_path so a future change to source_path resolution
            # (working copy, companion JPEG fallback, etc.) cannot silently
            # bypass RAW_DECODE_PRESERVE_HIGHLIGHTS for a RAW primary.
            primary_is_raw = (
                os.path.splitext(photo["filename"])[1].lower() in RAW_EXTENSIONS
            )
            raw_decode = RAW_DECODE_PRESERVE_HIGHLIGHTS if primary_is_raw else None
            load_kwargs = {"raw_decode": raw_decode} if raw_decode else {}
            img = load_image(source_path, max_size=None, **load_kwargs)
            expected_w, expected_h = 0, 0
            needs_companion = False
            if primary_is_raw:
                # libraw may return the embedded JPEG when it cannot
                # demosaic — that preview is typically much smaller than the
                # full-size companion JPEG, so the handoff would apply the
                # recipe to clipped pixels even when a usable sidecar exists.
                # Trigger the companion fallback when the RAW failed outright
                # or came back undersized (both axes checked, shared helper).
                expected_w, expected_h = _recipe_source_dimensions(photo)
                needs_companion = img is None or _image_is_smaller_than_expected(
                    img, expected_w, expected_h,
                )
            if needs_companion:
                # libraw can't decode this RAW (unsupported variant, corrupt
                # sensor data, no usable embedded JPEG) or only produced an
                # undersized embedded preview. Fall back to the full-size
                # companion JPEG so Open External still works for RAW+JPEG
                # pairs that have a usable handoff JPEG. Cache key stays on
                # the RAW source so a future RAW replacement (mtime bump)
                # re-tries the RAW; we accept that companion-only edits
                # won't invalidate this render — matching the cache
                # contract used elsewhere for RAW-primary photos.
                folder_path = folders.get(photo["folder_id"])
                companion_path = photo["companion_path"]
                if folder_path and companion_path:
                    companion_abs = os.path.join(folder_path, companion_path)
                    if (
                        os.path.exists(companion_abs)
                        and os.path.abspath(companion_abs)
                        != os.path.abspath(source_path)
                    ):
                        companion_img = load_image(companion_abs, max_size=None)
                        # Prefer companion when it covers the expected size on
                        # both axes — a long-edge-only check misses cases like
                        # a 6000x3376 embedded preview "tying" a 6000x4000
                        # sidecar and losing the short-edge content.
                        if _companion_image_can_replace_raw_result(
                            companion_img, img, expected_w, expected_h,
                        ):
                            if img is None:
                                log.info(
                                    "External-edit RAW decode failed for "
                                    "photo %s; falling back to companion "
                                    "JPEG %s",
                                    photo["id"], companion_abs,
                                )
                            else:
                                log.info(
                                    "External-edit RAW decode fell back to "
                                    "undersized embedded JPEG (%dx%d) for "
                                    "photo %s; using companion JPEG %s "
                                    "(%dx%d)",
                                    img.size[0], img.size[1], photo["id"],
                                    companion_abs,
                                    companion_img.size[0],
                                    companion_img.size[1],
                                )
                                img.close()
                            img = companion_img
                        elif companion_img is not None:
                            companion_img.close()
            if img is None:
                return None, f"{photo['filename']}: failed to load image"
            rendered = None
            tmp_path = None
            fd = None
            try:
                rendered = apply_recipe_to_loaded_image(
                    img, recipe,
                    native_size=_recipe_source_dimensions(photo),
                    local_mask=_local_masks.load_snapshot(
                        vireo_dir, photo["id"], recipe,
                    ),
                )
                quality = cfg.load().get("working_copy_quality", 92)
                fd, tmp_path = tempfile.mkstemp(
                    prefix=f".{photo['id']}.", suffix=".jpg.tmp", dir=out_dir,
                )
                os.close(fd)
                fd = None
                rendered.save(tmp_path, format="JPEG", quality=quality)
                os.replace(tmp_path, out_path)
                with open(meta_path, "w", encoding="utf-8") as f:
                    json.dump(expected_meta, f, sort_keys=True)
            except Exception:
                if fd is not None:
                    with contextlib.suppress(OSError):
                        os.close(fd)
                with contextlib.suppress(OSError):
                    if tmp_path:
                        os.unlink(tmp_path)
                raise
            finally:
                if rendered is not None:
                    rendered.close()
                if rendered is not img:
                    img.close()
            return out_path, None

        editors = cfg.get_editors()
        selected_editor = None
        editor_index = body.get("editor_index")
        if editor_index is None:
            # No index = use the first configured editor (or fall through to
            # the OS default if no editors are configured at all).
            selected_editor = editors[0] if editors else None
            editor = selected_editor["path"] if selected_editor else ""
        else:
            if not isinstance(editor_index, int) or isinstance(editor_index, bool):
                return json_error("editor_index must be an integer")
            if not editors:
                return json_error(
                    "No external editors configured. Add one in Settings.", 400
                )
            if editor_index < 0 or editor_index >= len(editors):
                return json_error(
                    f"editor_index {editor_index} out of range "
                    f"(have {len(editors)} editor(s))", 400
                )
            selected_editor = editors[editor_index]
            editor = selected_editor["path"]
        editor_path = os.path.expanduser(editor) if editor else ""

        # On macOS, an .app bundle is a directory — execing it raises EACCES.
        # Resolve the bundle when the user gives the parent folder (e.g.
        # /Applications/Adobe Lightroom Classic/) and route through `open -a`.
        app_bundle = None
        if sys.platform == "darwin" and editor_path:
            if editor_path.endswith(".app"):
                app_bundle = editor_path
            elif os.path.isdir(editor_path):
                try:
                    bundles = [
                        entry for entry in sorted(os.listdir(editor_path))
                        if entry.endswith(".app")
                    ]
                except OSError:
                    bundles = []
                if len(bundles) == 1:
                    app_bundle = os.path.join(editor_path, bundles[0])
                elif len(bundles) > 1:
                    return json_error(
                        f"Multiple .app bundles found in {editor_path} "
                        f"({', '.join(bundles)}). "
                        "Set the editor to a specific .app bundle.",
                        500,
                    )
                else:
                    return json_error(
                        f"No .app bundle found in {editor_path}. "
                        "Set the editor to the .app bundle directly.",
                        500,
                    )

        def _is_darktable_editor():
            parts = [
                selected_editor.get("name", "") if selected_editor else "",
                editor_path,
                app_bundle or "",
            ]
            return "darktable" in " ".join(parts).lower()

        file_paths = []
        for photo, path in photo_paths:
            handoff_path, handoff_error = _external_edit_handoff_path(photo, path)
            if handoff_error:
                return json_error(handoff_error, 500)
            file_paths.append(handoff_path)
        if _is_darktable_editor():
            from develop import convert_to_dng, is_nikon_high_efficiency_nef

            converted_paths = []
            for (photo, _original_path), input_path in zip(
                photo_paths, file_paths, strict=True,
            ):
                try:
                    metadata = (
                        json.loads(photo["exif_data"])
                        if photo["exif_data"] else None
                    )
                except (TypeError, json.JSONDecodeError):
                    metadata = None

                if not is_nikon_high_efficiency_nef(input_path, metadata=metadata):
                    converted_paths.append(input_path)
                    continue

                out_dir = os.path.join(vireo_dir, "external-dng", str(photo["id"]))
                stem = os.path.splitext(os.path.basename(input_path))[0]
                cached = os.path.join(out_dir, f"{stem}.dng")
                cached_alt = os.path.join(out_dir, f"{stem}.DNG")
                source_mtime = (
                    os.path.getmtime(input_path)
                    if os.path.exists(input_path) else 0
                )
                fresh_cached = None
                for candidate in (cached, cached_alt):
                    if (
                        os.path.isfile(candidate)
                        and os.path.getmtime(candidate) >= source_mtime
                    ):
                        log.info(
                            "Using cached DNG for darktable external editor: %s",
                            candidate,
                        )
                        fresh_cached = candidate
                        break
                if fresh_cached:
                    converted_paths.append(fresh_cached)
                    continue

                log.info(
                    "Converting Nikon HE NEF for darktable external editor: %s",
                    input_path,
                )
                conversion = convert_to_dng(
                    cfg.get("dng_converter_bin") or "",
                    input_path,
                    out_dir,
                )
                if not conversion["success"]:
                    return json_error(
                        "Nikon High Efficiency NEF detected, but DNG conversion failed: "
                        f"{conversion['error']}",
                        500,
                    )
                converted_paths.append(conversion["output_path"])
            file_paths = converted_paths

        try:
            if app_bundle:
                # `open -a` returns quickly after launching; capture the exit
                # so launch failures surface instead of disappearing silently.
                result = subprocess.run(
                    ["open", "-a", app_bundle] + file_paths,
                    capture_output=True, text=True, timeout=30,
                    **no_window_kwargs(),
                )
                if result.returncode != 0:
                    err = (result.stderr or result.stdout or "open failed").strip()
                    log.warning("open -a %s failed: %s", app_bundle, err)
                    return json_error(err, 500)
            elif editor_path:
                subprocess.Popen([editor_path] + file_paths, **no_window_kwargs())
            elif sys.platform == "darwin":
                result = subprocess.run(
                    ["open"] + file_paths,
                    capture_output=True, text=True, timeout=30,
                    **no_window_kwargs(),
                )
                if result.returncode != 0:
                    err = (result.stderr or result.stdout or "open failed").strip()
                    log.warning("open %s failed: %s", file_paths, err)
                    return json_error(err, 500)
            elif sys.platform == "win32":
                for fp in file_paths:
                    os.startfile(fp)
            else:
                for fp in file_paths:
                    subprocess.Popen(["xdg-open", fp], **no_window_kwargs())
        except Exception as e:
            log.warning("Failed to open external editor: %s", e)
            return json_error(str(e), 500)

        return jsonify({"opened": len(file_paths)})

    @app.route("/api/storage")
    def api_storage():
        """Comprehensive storage info for the storage management panel."""
        from classifier import CACHE_DIR as EMB_CACHE_DIR
        from models import DEFAULT_MODELS_DIR

        def _dir_stats(path):
            count = 0
            total = 0
            if os.path.isdir(path):
                for f in os.listdir(path):
                    fp = os.path.join(path, f)
                    if os.path.isfile(fp):
                        count += 1
                        total += os.path.getsize(fp)
            return {"count": count, "size": total, "path": path}

        def _dir_size_recursive(path):
            total = 0
            if os.path.isdir(path):
                for dirpath, dirnames, filenames in os.walk(path):
                    for f in filenames:
                        total += os.path.getsize(os.path.join(dirpath, f))
            return total

        db_size = os.path.getsize(db_path) if os.path.exists(db_path) else 0
        thumb = _dir_stats(app.config["THUMB_CACHE_DIR"])
        preview_dir = os.path.join(
            os.path.dirname(app.config["THUMB_CACHE_DIR"]), "previews"
        )
        preview = _dir_stats(preview_dir)
        emb = _dir_stats(EMB_CACHE_DIR)
        models_size = _dir_size_recursive(DEFAULT_MODELS_DIR)
        db = _get_db()
        offline_size = db.offline_original_total_bytes()
        offline_count_row = db.conn.execute(
            "SELECT COUNT(*) AS c FROM offline_originals WHERE status='cached'"
        ).fetchone()

        # HuggingFace cache — only count Vireo-relevant models
        hf_cache = os.path.expanduser("~/.cache/huggingface/hub")
        hf_size = 0
        hf_models = []
        if os.path.isdir(hf_cache):
            for d in os.listdir(hf_cache):
                if d.startswith("models--imageomics") or d.startswith(
                    "models--bioclip"
                ):
                    dp = os.path.join(hf_cache, d)
                    size = _dir_size_recursive(dp)
                    hf_size += size
                    hf_models.append(
                        {
                            "name": d.replace("models--", "").replace("--", "/"),
                            "size": size,
                        }
                    )

        total = (
            db_size
            + thumb["size"]
            + preview["size"]
            + emb["size"]
            + models_size
            + hf_size
            + offline_size
        )

        return jsonify(
            {
                "total": total,
                "database": {"size": db_size, "path": db_path},
                "thumbnails": thumb,
                "previews": preview,
                "embeddings": emb,
                "models": {"size": models_size, "path": DEFAULT_MODELS_DIR},
                "hf_cache": {"size": hf_size, "path": hf_cache, "models": hf_models},
                "offline_originals": {
                    "count": offline_count_row["c"],
                    "size": offline_size,
                    "path": os.path.join(os.path.dirname(app.config["THUMB_CACHE_DIR"]), "offline"),
                },
            }
        )

    @app.route("/api/storage/masks")
    def api_storage_masks():
        """Per-variant SAM mask summary (counts, bytes, active counts)
        plus stale-mask count for the storage dashboard."""
        import config as cfg

        db = _get_db()
        # Storage is global across all workspaces, so the stale floor
        # must be too. Using the active workspace's detector_confidence
        # would make stale_count flip when the user switches workspaces
        # and let masks valid under another workspace's lower floor
        # show up as stale. The minimum across workspaces is the most
        # permissive view: only mark a mask stale when no workspace
        # would still consider it fresh.
        min_detector_conf = db.min_detector_confidence_across_workspaces(
            cfg.load()
        )
        variants = db.mask_variants_summary()
        stale = db.find_stale_masks(detector_confidence=min_detector_conf)
        masks_dir = os.path.join(os.path.dirname(db_path), "masks")
        return jsonify({
            "variants": variants,
            "total_bytes": sum(v["bytes"] for v in variants),
            "stale_count": len(stale),
            "path": masks_dir,
        })

    @app.route("/api/storage/masks/delete-variant", methods=["POST"])
    def api_storage_masks_delete_variant():
        """Delete all photo_masks rows + files for the given variant.
        Returns 400 when the variant is currently active for any photo.
        """
        body = request.get_json(silent=True) or {}
        variant = body.get("variant", "")
        if not variant:
            return json_error("variant required")
        db = _get_db()
        try:
            n = db.delete_masks_for_variant(variant)
        except ValueError as e:
            return json_error(str(e), 400)
        log.info("Deleted %d masks for variant %s", n, variant)
        return jsonify({"ok": True, "deleted": n})

    @app.route("/api/storage/masks/delete-inactive", methods=["POST"])
    def api_storage_masks_delete_inactive():
        """Delete all non-active variant masks across all photos."""
        db = _get_db()
        n = db.delete_inactive_masks()
        log.info("Deleted %d inactive-variant masks", n)
        return jsonify({"ok": True, "deleted": n})

    @app.route("/api/storage/masks/delete-stale", methods=["POST"])
    def api_storage_masks_delete_stale():
        """Delete masks whose stored prompt no longer matches the current
        primary detection. Skips active variants."""
        import config as cfg

        db = _get_db()
        # Mirror /api/storage/masks: the deletion set must be a function
        # of the data, not of which workspace happens to be active.
        # Using the cross-workspace minimum keeps the count and the
        # delete in sync and prevents deleting masks that another
        # workspace's lower detector_confidence would still consider
        # fresh.
        min_detector_conf = db.min_detector_confidence_across_workspaces(
            cfg.load()
        )
        n = db.delete_stale_masks(detector_confidence=min_detector_conf)
        log.info("Deleted %d stale masks", n)
        # Edit-mask snapshots piggyback on the same sweep: unreferenced,
        # aged-out snapshot files (no current recipe or edit-history entry
        # points at them) are reclaimed alongside stale live masks.
        import local_masks
        # Snapshots live under dirname(THUMB_CACHE_DIR) — the same root the
        # snapshot POST endpoint writes to and every render call site reads
        # from — which is not always dirname(db_path) when create_app is
        # given a custom thumb-dir under a different parent.
        gc = local_masks.gc_edit_masks(
            db, os.path.dirname(app.config["THUMB_CACHE_DIR"])
        )
        if gc["deleted"]:
            log.info(
                "Deleted %d unreferenced edit-mask snapshots", gc["deleted"]
            )
        return jsonify({
            "ok": True, "deleted": n, "snapshots_deleted": gc["deleted"],
        })

    @app.route("/api/storage/files")
    def api_storage_files():
        """List individual files in a cache directory."""
        from classifier import CACHE_DIR as EMB_CACHE_DIR

        cache_type = request.args.get("type", "")
        dirs = {
            "thumbnails": app.config["THUMB_CACHE_DIR"],
            "previews": os.path.join(
                os.path.dirname(app.config["THUMB_CACHE_DIR"]), "previews"
            ),
            "embeddings": EMB_CACHE_DIR,
        }
        cache_dir = dirs.get(cache_type)
        if not cache_dir:
            return json_error("Unknown cache type")

        raw_limit = request.args.get("limit", type=int)
        limit = raw_limit if raw_limit and raw_limit > 0 else None

        # Load embedding manifest for display names
        manifest = {}
        if cache_type == "embeddings":
            from classifier import _load_manifest
            manifest = _load_manifest()

        files = []
        truncated = False
        if os.path.isdir(cache_dir):
            if limit is None:
                names = sorted(os.listdir(cache_dir))
                for f in names:
                    fp = os.path.join(cache_dir, f)
                    if os.path.isfile(fp) and f != "manifest.json":
                        entry = {"name": f, "size": os.path.getsize(fp)}
                        if f in manifest:
                            entry["meta"] = manifest[f]
                        files.append(entry)
            else:
                with os.scandir(cache_dir) as entries:
                    for entry_info in entries:
                        if entry_info.name == "manifest.json":
                            continue
                        if not entry_info.is_file():
                            continue
                        if len(files) >= limit:
                            truncated = True
                            break
                        stat = entry_info.stat()
                        entry = {"name": entry_info.name, "size": stat.st_size}
                        if entry_info.name in manifest:
                            entry["meta"] = manifest[entry_info.name]
                        files.append(entry)
        return jsonify({
            "type": cache_type,
            "path": cache_dir,
            "files": files,
            "truncated": truncated,
            "limit": limit,
        })

    @app.route("/api/storage/clear", methods=["POST"])
    def api_storage_clear():
        """Clear a specific cache."""
        import shutil

        body = request.get_json(silent=True) or {}
        cache_type = body.get("type", "")

        if cache_type == "previews":
            preview_dir = os.path.join(
                os.path.dirname(app.config["THUMB_CACHE_DIR"]), "previews"
            )
            if os.path.isdir(preview_dir):
                shutil.rmtree(preview_dir)
                log.info("Preview cache cleared")
            # Keep preview_cache table in sync with the filesystem so
            # Settings "Current usage" and eviction don't see phantoms.
            db = _get_db()
            db.conn.execute("DELETE FROM preview_cache")
            db.conn.commit()
            return jsonify({"ok": True})
        elif cache_type == "thumbnails":
            thumb_dir = app.config["THUMB_CACHE_DIR"]
            if os.path.isdir(thumb_dir):
                shutil.rmtree(thumb_dir)
                log.info("Thumbnail cache cleared")
            # Keep photos.thumb_path in sync with disk so the dashboard
            # coverage card and the pipeline plan don't see phantoms —
            # the column is the fast proxy that gates "thumbnail done"
            # in count_photos_missing_thumb, while the actual stage
            # gates on os.path.exists. Leaving thumb_path populated
            # after wiping the cache would make the Previews pill
            # report "Already done" even though the next run would
            # regenerate every thumbnail.
            db = _get_db()
            db.conn.execute(
                "UPDATE photos SET thumb_path = NULL "
                "WHERE thumb_path IS NOT NULL"
            )
            db.conn.commit()
            return jsonify({"ok": True})
        elif cache_type == "embeddings":
            from classifier import CACHE_DIR

            if os.path.isdir(CACHE_DIR):
                shutil.rmtree(CACHE_DIR)
                log.info("Embedding cache cleared")
            return jsonify({"ok": True})
        else:
            return json_error("Unknown cache type")

    @app.route("/api/storage/delete-files", methods=["POST"])
    def api_storage_delete_files():
        """Delete specific files from a cache directory."""
        from classifier import CACHE_DIR as EMB_CACHE_DIR

        body = request.get_json(silent=True) or {}
        cache_type = body.get("type", "")
        filenames = body.get("files", [])
        dirs = {
            "thumbnails": app.config["THUMB_CACHE_DIR"],
            "previews": os.path.join(
                os.path.dirname(app.config["THUMB_CACHE_DIR"]), "previews"
            ),
            "embeddings": EMB_CACHE_DIR,
        }
        cache_dir = dirs.get(cache_type)
        if not cache_dir:
            return json_error("Unknown cache type")
        if not filenames:
            return json_error("No files specified")

        deleted = 0
        # Keep preview_cache rows in sync when previews are deleted directly
        # via this endpoint (stats page). Matches {pid}_{size}.jpg only;
        # legacy {pid}.jpg files have no tracking row to remove.
        preview_rows_removed = 0
        # Keep photos.thumb_path in sync when individual thumbnail files
        # are removed — same reason as the storage/clear path: the column
        # is the planner's fast proxy and would otherwise report phantoms.
        thumb_ids_cleared = []
        if cache_type in ("previews", "thumbnails"):
            import re
            sized_pat = re.compile(r"^(\d+)_(\d+)\.jpg$")
            thumb_pat = re.compile(r"^(\d+)\.jpg$")
            db = _get_db()
        for fname in filenames:
            # Prevent path traversal
            safe = os.path.basename(fname)
            fp = os.path.join(cache_dir, safe)
            if os.path.isfile(fp):
                os.remove(fp)
                deleted += 1
                if cache_type == "previews":
                    m = sized_pat.match(safe)
                    if m:
                        db.preview_cache_delete(int(m.group(1)), int(m.group(2)))
                        preview_rows_removed += 1
                elif cache_type == "thumbnails":
                    m = thumb_pat.match(safe)
                    if m:
                        thumb_ids_cleared.append(int(m.group(1)))
        if cache_type == "previews" and preview_rows_removed:
            log.info("Removed %d preview_cache rows alongside files", preview_rows_removed)
        if cache_type == "thumbnails" and thumb_ids_cleared:
            # Chunk the IN-list under SQLite's SQLITE_MAX_VARIABLE_NUMBER cap
            # (999 on older builds). The storage UI's "delete selected" can
            # send thousands of files at once; a single statement with one
            # bind per id would raise OperationalError after the files have
            # already been removed, leaving photos.thumb_path out of sync
            # with disk.
            for chunk in _chunked(thumb_ids_cleared):
                placeholders = ",".join("?" for _ in chunk)
                db.conn.execute(
                    f"UPDATE photos SET thumb_path = NULL "
                    f"WHERE id IN ({placeholders})",
                    chunk,
                )
            db.conn.commit()
            log.info(
                "Cleared photos.thumb_path for %d photos alongside files",
                len(thumb_ids_cleared),
            )
        log.info("Deleted %d files from %s cache", deleted, cache_type)
        return jsonify({"ok": True, "deleted": deleted})

    def _recommended_preview_cache_mb(db):
        """Recommend a quota that fits one preview per photo across the
        whole library.

        Uses the measured average bytes-per-preview from the existing
        ``preview_cache`` rows when available, otherwise falls back to
        500 KB (a typical 1920px JPEG at quality 90). Photos are global
        across workspaces so this is a library-wide count, not
        workspace-scoped.

        Returns 0 when the photos table is empty (avoids a "recommended
        0 MB" surprise on a fresh install).
        """
        photo_count = db.conn.execute(
            "SELECT COUNT(*) FROM photos"
        ).fetchone()[0]
        if not photo_count:
            return 0
        avg_row = db.conn.execute(
            "SELECT AVG(bytes) AS a FROM preview_cache WHERE bytes > 0"
        ).fetchone()
        avg_bytes = (avg_row["a"] if avg_row and avg_row["a"] else 500 * 1024)
        recommended_bytes = photo_count * avg_bytes
        return max(1, int(recommended_bytes / 1024 / 1024) + 1)

    @app.route("/api/preview-cache")
    def api_preview_cache():
        """Return counts and totals from the preview_cache table, plus quota."""
        import config as cfg
        db = _get_db()
        count_row = db.conn.execute(
            "SELECT COUNT(*) AS c FROM preview_cache"
        ).fetchone()
        total = db.preview_cache_total_bytes()
        quota_mb = cfg.load().get("preview_cache_max_mb", 20480)
        return jsonify({
            "count": count_row["c"],
            "total_size": total,
            "quota_bytes": int(quota_mb) * 1024 * 1024,
            "recommended_mb": _recommended_preview_cache_mb(db),
        })

    @app.route("/api/preview-cache/clear", methods=["POST"])
    def api_preview_cache_clear():
        """Delete every preview_cache file and row, including legacy and
        untracked files in the previews directory.

        Tracked rows whose on-disk files couldn't be unlinked (e.g. a
        locked or permission-restricted file) are kept so accounting
        and future eviction still reflect the leaked bytes — otherwise
        /api/preview-cache would under-report and eviction would stop
        targeting them.
        """
        import re

        db = _get_db()
        vireo_dir = os.path.dirname(app.config["THUMB_CACHE_DIR"])
        preview_dir = os.path.join(vireo_dir, "previews")

        count_row = db.conn.execute(
            "SELECT COUNT(*) AS c FROM preview_cache"
        ).fetchone()
        tracked = count_row["c"]

        # Matches {id}.jpg (legacy /full cache) and {id}_{size}.jpg (current).
        pattern = re.compile(r"^(\d+)(?:_(\d+))?\.jpg$")
        sized_pat = re.compile(r"^(\d+)_(\d+)\.jpg$")
        files_removed = 0
        failed_tracked = []  # (photo_id, size) tuples for sized files we couldn't unlink
        if os.path.isdir(preview_dir):
            for fname in os.listdir(preview_dir):
                if not pattern.match(fname):
                    continue
                try:
                    os.remove(os.path.join(preview_dir, fname))
                    files_removed += 1
                except OSError:
                    m = sized_pat.match(fname)
                    if m:
                        failed_tracked.append((int(m.group(1)), int(m.group(2))))

        if failed_tracked:
            # Stage failed keys in a temp table so the DELETE isn't a giant
            # NOT IN clause that blows past SQLite's default variable limit
            # (~999) with a few hundred unlinkable files. Insert in chunks
            # of 400 pairs (800 bind parameters) for the same reason.
            db.conn.execute(
                "CREATE TEMP TABLE _pc_failed (photo_id INTEGER, size INTEGER)"
            )
            try:
                CHUNK = 400
                for i in range(0, len(failed_tracked), CHUNK):
                    batch = failed_tracked[i:i + CHUNK]
                    placeholders = ",".join(["(?,?)"] * len(batch))
                    flat = [v for pair in batch for v in pair]
                    db.conn.execute(
                        f"INSERT INTO _pc_failed (photo_id, size) VALUES {placeholders}",
                        flat,
                    )
                db.conn.execute(
                    "DELETE FROM preview_cache WHERE (photo_id, size) NOT IN "
                    "(SELECT photo_id, size FROM _pc_failed)"
                )
            finally:
                db.conn.execute("DROP TABLE _pc_failed")
        else:
            db.conn.execute("DELETE FROM preview_cache")
        db.conn.commit()

        remaining = db.conn.execute(
            "SELECT COUNT(*) AS c FROM preview_cache"
        ).fetchone()["c"]
        cleared = tracked - remaining

        return jsonify({
            "cleared": cleared,
            "files_removed": files_removed,
            "failed": len(failed_tracked),
        })

